import { ethers } from "ethers";
import { useState } from "react";

// Import your sub-components
import IssueCertificate from "./components/IssueCertificate"; 
import VerifyCertificate from "./components/VerifyCertificate";

// Import the JSON artifact
import CertificateVerifierArtifact from "./artifacts/contracts/Certificate.sol/CertificateVerifier.json";

// Extract ABI and Address
const abi = CertificateVerifierArtifact.abi;
const contractAddress = "0x5FbDB2315678afecb367f032d93F642f64180aa3";

function App() {
  return (
    <div style={{ padding: "50px", fontFamily: "sans-serif", backgroundColor: "#f9f9f9", minHeight: "100vh" }}>
      <h1 style={{ textAlign: "center", color: "#333" }}>🎓 Academic Document Verifier</h1>
      
      <div style={{ 
        display: "flex", 
        justifyContent: "space-around", 
        marginTop: "50px",
        flexWrap: "wrap",
        gap: "20px"
      }}>
        
        {/* LEFT SIDE: COLLEGE PORTAL (ISSUING) */}
        <div style={containerStyle}>
          <h2>College Admin</h2>
          <p style={{fontSize: "0.9rem", color: "#666"}}>Use this to mint new certificates on the blockchain.</p>
          <hr />
          <IssueCertificate contractAddress={contractAddress} abi={abi} />
        </div>

        {/* RIGHT SIDE: VERIFIER PORTAL (SEARCHING) */}
        <div style={containerStyle}>
          <h2>Verifier Portal</h2>
          <p style={{fontSize: "0.9rem", color: "#666"}}>Employers can verify the authenticity of a document here.</p>
          <hr />
          <VerifyCertificate contractAddress={contractAddress} abi={abi} />
        </div>

      </div>
    </div>
  );
}

// Simple styling object for the two portal boxes
const containerStyle = {
  background: "#fff",
  padding: "30px",
  borderRadius: "12px",
  boxShadow: "0 4px 15px rgba(0,0,0,0.1)",
  width: "400px"
};

export default App;
